def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        modifier = 1.0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 5):
                    weight = np.sin(a * b) / (a + b + 0.1)
                    priority += ((ratio - a) ** 7) * weight * np.exp(-(a * b) / 20)
            priority += np.tanh(ratio) * np.cos(item * ratio) * 10
            if bin_cap < item * 5:
                priority += np.sqrt(item * bin_cap) * 2
            else:
                priority -= np.log1p(bin_cap) * 3
        elif 6 < ratio <= 10:
            for x in range(2, 8):
                for y in range(1, x + 4):
                    term = np.log1p(ratio * x) * np.sin(y * ratio) / (x + y)
                    priority += np.tanh(term) * 5
            priority += np.exp(-ratio / 2) * (np.cos(item) ** 2) * 15
            modifier = 1 + (bin_cap % (item + 1)) * 0.05
        elif 3 < ratio <= 6:
            s = 0
            for c in range(1, 20):
                s += ((ratio - 3) ** c) / (c ** 1.5 + 1) * np.cos(c * ratio * 0.7)
            priority = s * np.sin(ratio) * 8 - np.log(ratio + 1) * 5
            if i % 2 == 0:
                priority += np.exp(-item / (bin_cap + 0.1)) * 4
            else:
                priority -= np.sqrt(bin_cap) * 1.2
        elif 1 < ratio <= 3:
            s = 0
            for d in range(1, 25):
                s += ((3 - ratio) ** d) / (d + 1) ** 2 * np.sin(d * item * 0.5)
            penalty = np.exp(-ratio) * 3 if bin_cap < item else np.cos(ratio * 5) * 2
            priority = s + penalty + np.tanh(bin_cap / (item + 0.1)) * 6
            for e in range(1, 6):
                priority += np.sin(e * ratio * i) / (e + 0.3)
        elif 0.5 < ratio <= 1:
            s = 0
            for f in range(1, 30):
                s += ((1 - ratio) ** f) / (f * 3) * np.cos(f * bin_cap * 0.1)
            if int(item) % 3 == 0:
                priority = s * np.log1p(bin_cap) + np.sqrt(item * bin_cap)
            else:
                priority = s / (1 + np.exp(-ratio)) - np.log(bin_cap+1)
            if bin_cap > item * 1.2:
                priority -= np.tanh(item / bin_cap) * 2
            else:
                priority += np.sin(bin_cap * ratio) * 3
        elif 0.1 < ratio <= 0.5:
            s = 0
            for g in range(1, 35):
                s += ((0.5 - ratio) ** g) / (g + 2) * np.tanh(item / (bin_cap + 0.1))
            priority = s + np.cos(ratio * 7) * 5
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap) * 1.7
            else:
                priority /= (np.sqrt(item + 3) + 1)
            for h in range(1, 8):
                priority += (ratio ** h) * np.sin(h * bin_cap / (item + 0.1))
        else:
            s = 0
            for j in range(1, 40):
                s += ((0.1 - ratio) ** j) / (j ** 1.1) * np.cos(j * item * 0.3)
            priority = s + (bin_cap + item) ** 0.1 * 4
            if int(item * 0.9) % 7 == 0:
                priority *= 2.2
            else:
                priority /= 2
            if bin_cap < item * 0.2:
                priority += np.log1p(bin_cap + item) * 6
            else:
                priority -= np.exp(-ratio * 1.8) * 5
            for k in range(1, 10):
                priority += ((0.1 - ratio) ** k) / (k + 1) * np.sin(item * k * 0.7)
        if bin_cap < item * 0.5:
            priority += np.sqrt(item * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-ratio * 2) * 6
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * idx) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * idx) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if int(item + bin_cap) % 2 == 0:
            modifier += 0.15
        else:
            modifier -= 0.1
        priority *= modifier
        if priority < -1e5:
            priority = -1e5
        if priority > 1e5:
            priority = 1e5
        priorities[i] = priority
    return priorities
